// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.math.BigDecimal;
import java.time.LocalDate;
import java.util.List;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.LmdbStore;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Differential tests for native evaluation of non-COUNT aggregates (SUM, MIN, MAX, AVG): every query is evaluated on
 * the native LMDB engine and on the generic evaluator, and results must match — including SPARQL type-error semantics
 * (a non-numeric value poisons SUM/AVG and drops the binding), empty-group semantics (SUM/AVG yield 0, MIN/MAX yield no
 * binding), numeric type promotion, and DISTINCT. Tests marked with assertNativeAggregation additionally require that
 * the native aggregate compiler actually accepted the query, so they fail while the feature is missing.
 */
public class LmdbNativeNonCountAggregateTest {

	private static final String EX = "http://example.com/";
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI cat = vf.createIRI(EX, "cat");
			IRI price = vf.createIRI(EX, "price");
			IRI built = vf.createIRI(EX, "built");
			IRI label = vf.createIRI(EX, "label");
			IRI link = vf.createIRI(EX, "link");

			IRI a = vf.createIRI(EX, "catA");
			IRI b = vf.createIRI(EX, "catB");
			IRI c = vf.createIRI(EX, "catC");
			IRI d = vf.createIRI(EX, "catD");

			// catA: clean ints, one duplicated term (10 appears on two subjects)
			conn.add(vf.createIRI(EX, "item1"), cat, a);
			conn.add(vf.createIRI(EX, "item1"), price, vf.createLiteral(10));
			conn.add(vf.createIRI(EX, "item2"), cat, a);
			conn.add(vf.createIRI(EX, "item2"), price, vf.createLiteral(10));
			conn.add(vf.createIRI(EX, "item3"), cat, a);
			conn.add(vf.createIRI(EX, "item3"), price, vf.createLiteral(new BigDecimal("2.5")));
			// catB: contains a non-numeric price -> SUM/AVG type error, binding dropped
			conn.add(vf.createIRI(EX, "item4"), cat, b);
			conn.add(vf.createIRI(EX, "item4"), price, vf.createLiteral(7));
			conn.add(vf.createIRI(EX, "item5"), cat, b);
			conn.add(vf.createIRI(EX, "item5"), price, vf.createLiteral("oops"));
			// catC: no price at all -> SUM/AVG 0, MIN/MAX unbound under OPTIONAL
			conn.add(vf.createIRI(EX, "item6"), cat, c);
			// catD: double -> promotion to double
			conn.add(vf.createIRI(EX, "item7"), cat, d);
			conn.add(vf.createIRI(EX, "item7"), price, vf.createLiteral(100.0d));

			// dates and strings for MIN/MAX
			conn.add(vf.createIRI(EX, "item1"), built, vf.createLiteral(LocalDate.of(2020, 1, 5)));
			conn.add(vf.createIRI(EX, "item2"), built, vf.createLiteral(LocalDate.of(1999, 12, 31)));
			conn.add(vf.createIRI(EX, "item3"), built, vf.createLiteral(LocalDate.of(2024, 6, 1)));
			conn.add(vf.createIRI(EX, "item1"), label, vf.createLiteral("alpha"));
			conn.add(vf.createIRI(EX, "item2"), label, vf.createLiteral("beta"));

			// star-join fan-out so a factorized tail would engage for COUNT-style plans
			conn.add(vf.createIRI(EX, "item1"), link, vf.createIRI(EX, "n1"));
			conn.add(vf.createIRI(EX, "item1"), link, vf.createIRI(EX, "n2"));
			conn.add(vf.createIRI(EX, "item2"), link, vf.createIRI(EX, "n1"));
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	private List<String> rows(String query) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			return result.stream().map(Object::toString).sorted().collect(Collectors.toList());
		}
	}

	private void assertSameAsGeneric(String query) {
		List<String> nativeRows = rows(query);
		String previous = System.getProperty(NATIVE_FLAG);
		List<String> genericRows;
		try {
			System.setProperty(NATIVE_FLAG, "false");
			genericRows = rows(query);
		} finally {
			if (previous == null) {
				System.clearProperty(NATIVE_FLAG);
			} else {
				System.setProperty(NATIVE_FLAG, previous);
			}
		}
		assertThat(nativeRows).as("native vs generic for:\n" + query).isEqualTo(genericRows);
	}

	/** Asserts parity AND that the native aggregate compiler accepted the query. */
	private void assertNativeAggregation(String query) {
		long before = LmdbNativeAggregateCompiler.COMPILED.get();
		assertSameAsGeneric(query);
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("native aggregate compiler should accept:\n" + query)
				.isGreaterThan(before);
	}

	private static String q(String body) {
		return "PREFIX ex: <" + EX + ">\nPREFIX xsd: <http://www.w3.org/2001/XMLSchema#>\n" + body;
	}

	@Test
	public void globalSum() {
		assertNativeAggregation(q("SELECT (SUM(?v) AS ?sum) WHERE { ?s ex:price ?v }"));
	}

	@Test
	public void groupedSum() {
		assertNativeAggregation(q("SELECT ?c (SUM(?v) AS ?sum) WHERE { ?s ex:cat ?c ; ex:price ?v } GROUP BY ?c"));
	}

	@Test
	public void groupedSumWithTypeErrorGroup() {
		// catB contains "oops" -> its ?sum binding must be dropped, others kept
		assertSameAsGeneric(q("SELECT ?c (SUM(?v) AS ?sum) WHERE { ?s ex:cat ?c ; ex:price ?v } GROUP BY ?c"));
	}

	@Test
	public void distinctSum() {
		// duplicate term 10 must be summed once
		assertNativeAggregation(
				q("SELECT ?c (SUM(DISTINCT ?v) AS ?sum) WHERE { ?s ex:cat ?c ; ex:price ?v } GROUP BY ?c"));
	}

	@Test
	public void globalAvg() {
		assertNativeAggregation(q("SELECT (AVG(?v) AS ?avg) WHERE { ?s ex:price ?v . ?s ex:cat ex:catA }"));
	}

	@Test
	public void groupedAvgOverOptional() {
		// catC has no prices: AVG must be 0, SUM must be 0, MIN/MAX unbound
		assertNativeAggregation(q("SELECT ?c (AVG(?v) AS ?avg) (SUM(?v) AS ?sum) (MIN(?v) AS ?min) "
				+ "(MAX(?v) AS ?max) WHERE { ?s ex:cat ?c . OPTIONAL { ?s ex:price ?v } } GROUP BY ?c"));
	}

	@Test
	public void distinctAvg() {
		assertNativeAggregation(
				q("SELECT ?c (AVG(DISTINCT ?v) AS ?avg) WHERE { ?s ex:cat ?c ; ex:price ?v } GROUP BY ?c"));
	}

	@Test
	public void minMaxIntsAndDecimals() {
		assertNativeAggregation(q("SELECT (MIN(?v) AS ?min) (MAX(?v) AS ?max) WHERE { ?s ex:price ?v . "
				+ "FILTER(isNumeric(?v)) }"));
	}

	@Test
	public void minMaxDates() {
		assertNativeAggregation(q("SELECT (MIN(?d) AS ?min) (MAX(?d) AS ?max) WHERE { ?s ex:built ?d }"));
	}

	@Test
	public void maxStrings() {
		assertNativeAggregation(q("SELECT (MAX(?l) AS ?max) WHERE { ?s ex:label ?l }"));
	}

	@Test
	public void maxOverIris() {
		assertNativeAggregation(q("SELECT (MAX(?s) AS ?max) WHERE { ?s ex:price ?v }"));
	}

	@Test
	public void mixedCountAndSum() {
		assertNativeAggregation(q("SELECT ?c (COUNT(?s) AS ?n) (SUM(?v) AS ?sum) WHERE { "
				+ "?s ex:cat ?c ; ex:price ?v } GROUP BY ?c"));
	}

	@Test
	public void havingOverSum() {
		assertNativeAggregation(q("SELECT ?c (SUM(?v) AS ?sum) WHERE { ?s ex:cat ?c ; ex:price ?v } "
				+ "GROUP BY ?c HAVING(SUM(?v) > 10)"));
	}

	@Test
	public void havingOverAvgAnonymous() {
		assertSameAsGeneric(q("SELECT ?c WHERE { ?s ex:cat ?c ; ex:price ?v } "
				+ "GROUP BY ?c HAVING(AVG(?v) >= 5)"));
	}

	@Test
	public void sumOverStarJoinTail() {
		// the link fan-out makes ?v the natural factorized-tail candidate for COUNT plans;
		// SUM must not use the count-product shortcut
		assertNativeAggregation(q("SELECT ?s (SUM(?v) AS ?sum) (COUNT(?o) AS ?links) WHERE { "
				+ "?s ex:price ?v ; ex:link ?o } GROUP BY ?s"));
	}

	@Test
	public void sumOfDoublePromotion() {
		assertSameAsGeneric(q("SELECT (SUM(?v) AS ?sum) WHERE { ?s ex:price ?v . FILTER(isNumeric(?v)) }"));
	}

	@Test
	public void valuesConstantMissingFromStore() {
		// "8"^^xsd:integer exists nowhere in the store: the VALUES row needs a plan-local synthetic id and
		// the >= filter must evaluate through the generic value-materializing path
		assertNativeAggregation(q("SELECT (SUM(?v) AS ?sum) WHERE { VALUES ?minV { 8 } ?s ex:price ?v . "
				+ "FILTER(?v >= ?minV) }"));
	}

	@Test
	public void valuesConstantMissingFromStoreAsGroupKey() {
		// synthetic ids as group keys must materialize back to the original literals in result rows
		assertSameAsGeneric(q("SELECT ?minV (COUNT(?s) AS ?n) WHERE { VALUES ?minV { 8 9 } ?s ex:price ?v . "
				+ "FILTER(?v >= ?minV) } GROUP BY ?minV"));
	}

	@Test
	public void emptyResultGlobalAggregates() {
		assertNativeAggregation(q("SELECT (SUM(?v) AS ?sum) (AVG(?v) AS ?avg) (MIN(?v) AS ?min) WHERE { "
				+ "?s ex:cat ex:doesNotExist ; ex:price ?v }"));
	}
}
